// イベントをマージして重複を除去
const iosDiscordEvents = $input.all()[0].json.events || [];
const loveSwiftEvents = $input.all()[1].json.events || [];

const allEvents = [...iosDiscordEvents, ...loveSwiftEvents];
const uniqueEvents = [];
const seenIds = new Set();

for (const event of allEvents) {
  if (!seenIds.has(event.event_id)) {
    seenIds.add(event.event_id);
    uniqueEvents.push(event);
  }
}

// 日付でソート
uniqueEvents.sort((a, b) => new Date(a.started_at) - new Date(b.started_at));

// 今後のイベントのみフィルタ
const now = new Date();
const upcomingEvents = uniqueEvents.filter(e => new Date(e.started_at) > now);

return { events: upcomingEvents };

// 新しいイベントをチェック
const events = $input.all()[0].json.events;
const cache = $getWorkflowStaticData('notified_events') || [];
const newEvents = [];

for (const event of events) {
  if (!cache.includes(event.event_id)) {
    newEvents.push(event);
    cache.push(event.event_id);
  }
}

// キャッシュを更新（最新100件のみ保持）
$setWorkflowStaticData('notified_events', cache.slice(-100));

return { newEvents, hasNew: newEvents.length > 0 };

// Discord用メッセージフォーマット
const newEvents = $input.all()[0].json.newEvents;

if (newEvents.length === 0) {
  return { skip: true };
}

const embeds = newEvents.slice(0, 5).map(event => {
  const startTime = new Date(event.started_at);
  const dateStr = startTime.toLocaleDateString('ja-JP', {
    month: 'numeric',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit'
  });

  return {
    title: event.title,
    url: event.event_url,
    description: event.catch || '',
    color: 0x007AFF, // iOS Blue
    fields: [
      {
        name: '📅 日時',
        value: dateStr,
        inline: true
      },
      {
        name: '📍 場所',
        value: event.place || 'オンライン',
        inline: true
      },
      {
        name: '👥 参加者',
        value: `${event.accepted}/${event.limit || '∞'}`,
        inline: true
      }
    ],
    footer: {
      text: event.series ? event.series.title : 'iOS Community Event'
    },
    timestamp: new Date().toISOString()
  };
});

return {
  content: '🎉 **新しいiOSイベントが公開されました！**',
  embeds
};

// Twitter投稿用フォーマット
const newEvents = $input.all()[0].json.newEvents;

if (newEvents.length === 0) {
  return { skip: true };
}

const event = newEvents[0]; // 最新のイベントのみ
const startTime = new Date(event.started_at);
const dateStr = startTime.toLocaleDateString('ja-JP', {
  month: 'numeric',
  day: 'numeric',
  hour: 'numeric',
  minute: '2-digit'
});

const tweet = `🎉 iOS イベント情報\n\n${event.title}\n📅 ${dateStr}\n📍 ${event.place || 'オンライン'}\n\n詳細・申込👇\n${event.event_url}\n\n#iOS #Swift #iOSDev #東京`;

return { tweet, event_url: event.event_url };

// カレンダー Markdown 生成
const events = $input.all()[0].json.events;

let markdown = '# 📅 iOS コミュニティイベントカレンダー\n\n';
markdown += '## 今後のイベント\n\n';
markdown += '| 日時 | イベント | 場所 | 参加者 | 申込 |\n';
markdown += '|------|----------|------|--------|------|\n';

events.slice(0, 20).forEach(event => {
  const startTime = new Date(event.started_at);
  const dateStr = startTime.toLocaleDateString('ja-JP', {
    month: 'numeric',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit'
  });

  const title = `[${event.title.substring(0, 30)}](${event.event_url})`;
  const place = (event.place || 'オンライン').substring(0, 20);
  const participants = `${event.accepted}/${event.limit || '∞'}`;
  const status = event.limit && event.accepted >= event.limit ? '🔴 満席' : '🔵 受付中';

  markdown += `| ${dateStr} | ${title} | ${place} | ${participants} | ${status} |\n`;
});

markdown += `\n\n*最終更新: ${new Date().toISOString()}*`;

return { markdown, filename: 'ios-events-calendar.md' };
